/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Manifesto Eletrônico Documentos Fiscais"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &MDFeNum.IsEmpty() print printBlockFilterMDFeNum EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If not &MdfeVeiPlaTra.IsEmpty() print printBlockFilterMdfeVeiPlaTra EndIf If not &MDFeDtaEms.IsEmpty() print printBlockFilterMDFeDtaEms EndIf If not &MDFeDtaEms_To.IsEmpty() &MDFeDtaEms_To_Description = format('%1 (%2)', "Emi.", "à") print printBlockFilterMDFeDtaEms_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MDFESTS' &MDFeSts1.FromString(&GridStateDynamicFilter.Value) If not &MDFeSts1.IsEmpty() &FilterMDFeSts1ValueDescription = &MDFeSts1.EnumerationDescription()
&FilterMDFeStsValueDescription = &FilterMDFeSts1ValueDescription print printBlockFilterMDFeSts EndIf Case &DynamicFiltersSelector1 = !'MDFEORIUFECOD' &MDFeOriUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &MDFeOriUfeCod1.IsEmpty() &MDFeOriUfeCod = &MDFeOriUfeCod1 print printBlockFilterMDFeOriUfeCod EndIf Case &DynamicFiltersSelector1 = !'MDFEDSTUFECOD' &MDFeDstUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &MDFeDstUfeCod1.IsEmpty() &MDFeDstUfeCod = &MDFeDstUfeCod1 print printBlockFilterMDFeDstUfeCod EndIf Case &DynamicFiltersSelector1 = !'MDFECOD' &MDFeCod1.FromString(&GridStateDynamicFilter.Value) If not &MDFeCod1.IsEmpty() &MDFeCod = &MDFeCod1 print printBlockFilterMDFeCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MDFESTS' &MDFeSts2.FromString(&GridStateDynamicFilter.Value) If not &MDFeSts2.IsEmpty() &FilterMDFeSts2ValueDescription = &MDFeSts2.EnumerationDescription()
&FilterMDFeStsValueDescription = &FilterMDFeSts2ValueDescription print printBlockFilterMDFeSts EndIf Case &DynamicFiltersSelector2 = !'MDFEORIUFECOD' &MDFeOriUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &MDFeOriUfeCod2.IsEmpty() &MDFeOriUfeCod = &MDFeOriUfeCod2 print printBlockFilterMDFeOriUfeCod EndIf Case &DynamicFiltersSelector2 = !'MDFEDSTUFECOD' &MDFeDstUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &MDFeDstUfeCod2.IsEmpty() &MDFeDstUfeCod = &MDFeDstUfeCod2 print printBlockFilterMDFeDstUfeCod EndIf Case &DynamicFiltersSelector2 = !'MDFECOD' &MDFeCod2.FromString(&GridStateDynamicFilter.Value) If not &MDFeCod2.IsEmpty() &MDFeCod = &MDFeCod2 print printBlockFilterMDFeCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MDFESTS' &MDFeSts3.FromString(&GridStateDynamicFilter.Value) If not &MDFeSts3.IsEmpty() &FilterMDFeSts3ValueDescription = &MDFeSts3.EnumerationDescription()
&FilterMDFeStsValueDescription = &FilterMDFeSts3ValueDescription print printBlockFilterMDFeSts EndIf Case &DynamicFiltersSelector3 = !'MDFEORIUFECOD' &MDFeOriUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &MDFeOriUfeCod3.IsEmpty() &MDFeOriUfeCod = &MDFeOriUfeCod3 print printBlockFilterMDFeOriUfeCod EndIf Case &DynamicFiltersSelector3 = !'MDFEDSTUFECOD' &MDFeDstUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &MDFeDstUfeCod3.IsEmpty() &MDFeDstUfeCod = &MDFeDstUfeCod3 print printBlockFilterMDFeDstUfeCod EndIf Case &DynamicFiltersSelector3 = !'MDFECOD' &MDFeCod3.FromString(&GridStateDynamicFilter.Value) If not &MDFeCod3.IsEmpty() &MDFeCod = &MDFeCod3 print printBlockFilterMDFeCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (MDFeCod) when &OrderedBy = 1 order MDFeNum when &OrderedBy = 2 AND &OrderedDsc = False order (MDFeNum) when &OrderedBy = 2 AND &OrderedDsc = True order MDFeDtaEms when &OrderedBy = 3 AND &OrderedDsc = False order (MDFeDtaEms) when &OrderedBy = 3 AND &OrderedDsc = True order MDFeVlrTot when &OrderedBy = 4 AND &OrderedDsc = False order (MDFeVlrTot) when &OrderedBy = 4 AND &OrderedDsc = True
using DSWWMDFe(&MDFeNum, &FilCod, &MdfeVeiPlaTra, &MDFeDtaEms, &MDFeDtaEms_To, &DynamicFiltersSelector1 , &MDFeSts1, &MDFeOriUfeCod1, &MDFeDstUfeCod1, &MDFeCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &MDFeSts2, &MDFeOriUfeCod2, &MDFeDstUfeCod2, &MDFeCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3 , &MDFeSts3, &MDFeOriUfeCod3, &MDFeDstUfeCod3, &MDFeCod3) &MDFeStsDescription = MDFeSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWMDFeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWMDFeGridState")) Else &GridState.FromXml(&Session.Get(!"WWMDFeGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"MDFENUM" &MDFeNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MDFEVEIPLATRA" &MdfeVeiPlaTra.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MDFEDTAEMS" &MDFeDtaEms.FromString(&GridStateFilterValue.Value) &MDFeDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
